    {"offset": {"line": 33, "column": 0}, "map": {"version":3,"sources":["file://C%3A/Users/Abdalmoute/OneDrive/Desktop/unijoy-events/frontend/components/ui/button.tsx"],"sourcesContent":["import * as React from \"react\"\nimport { Slot } from \"@radix-ui/react-slot\"\nimport { cva, type VariantProps } from \"class-variance-authority\"\n\nimport { cn } from \"@/lib/utils\"\n\nconst buttonVariants = cva(\n  \"inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive\",\n  {\n    variants: {\n      variant: {\n        default:\n          \"bg-primary text-primary-foreground shadow-xs hover:bg-primary/90\",\n        destructive:\n          \"bg-destructive text-white shadow-xs hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60\",\n        outline:\n          \"border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground dark:bg-input/30 dark:border-input dark:hover:bg-input/50\",\n        secondary:\n          \"bg-secondary text-secondary-foreground shadow-xs hover:bg-secondary/80\",\n        ghost:\n          \"hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50\",\n        link: \"text-primary underline-offset-4 hover:underline\",\n      },\n      size: {\n        default: \"h-9 px-4 py-2 has-[>svg]:px-3\",\n        sm: \"h-8 rounded-md gap-1.5 px-3 has-[>svg]:px-2.5\",\n        lg: \"h-10 rounded-md px-6 has-[>svg]:px-4\",\n        icon: \"size-9\",\n      },\n    },\n    defaultVariants: {\n      variant: \"default\",\n      size: \"default\",\n    },\n  }\n)\n\nfunction Button({\n  className,\n  variant,\n  size,\n  asChild = false,\n  ...props\n}: React.ComponentProps<\"button\"> &\n  VariantProps<typeof buttonVariants> & {\n    asChild?: boolean\n  }) {\n  const Comp = asChild ? Slot : \"button\"\n\n  return (\n    <Comp\n      data-slot=\"button\"\n      className={cn(buttonVariants({ variant, size, className }))}\n      {...props}\n    />\n  )\n}\n\nexport { Button, buttonVariants }\n"],"names":[],"mappings":";;;;;AACA;AACA;AAEA;;;;;AAEA,MAAM,iBAAiB,CAAA,GAAA,gKAAA,CAAA,MAAG,AAAD,EACvB,+bACA;IACE,UAAU;QACR,SAAS;YACP,SACE;YACF,aACE;YACF,SACE;YACF,WACE;YACF,OACE;YACF,MAAM;QACR;QACA,MAAM;YACJ,SAAS;YACT,IAAI;YACJ,IAAI;YACJ,MAAM;QACR;IACF;IACA,iBAAiB;QACf,SAAS;QACT,MAAM;IACR;AACF;AAGF,SAAS,OAAO,EACd,SAAS,EACT,OAAO,EACP,IAAI,EACJ,UAAU,KAAK,EACf,GAAG,OAIF;IACD,MAAM,OAAO,UAAU,gKAAA,CAAA,OAAI,GAAG;IAE9B,qBACE,8OAAC;QACC,aAAU;QACV,WAAW,CAAA,GAAA,6GAAA,CAAA,KAAE,AAAD,EAAE,eAAe;YAAE;YAAS;YAAM;QAAU;QACvD,GAAG,KAAK;;;;;;AAGf","debugId":null}},
    {"offset": {"line": 90, "column": 0}, "map": {"version":3,"sources":["file://C%3A/Users/Abdalmoute/OneDrive/Desktop/unijoy-events/frontend/app/profile/edit/page.tsx"],"sourcesContent":["'use client';\r\nimport { useEffect, useState } from 'react';\r\nimport { zodResolver } from '@hookform/resolvers/zod';\r\nimport { useToast } from '@/hooks/use-toast';\r\nimport { useForm } from 'react-hook-form';\r\nimport { z } from 'zod';\r\nimport { Input } from '@/components/ui/input';\r\nimport { Textarea } from '@/components/ui/textarea';\r\nimport { Button } from '@/components/ui/button';\r\nimport { motion } from 'framer-motion';\r\nimport { useAuth } from '@/context/AuthContext';\r\n\r\nconst profileSchema = z.object({\r\n  name: z.string().min(2, 'Name must be at least 2 characters'),\r\n  email: z.string().email('Invalid email address'),\r\n});\r\n\r\nexport default function EditProfilePage() {\r\n  const { token, detailsProfile } = useAuth();\r\n  const { toast } = useToast();\r\n  const [loading, setLoading] = useState(false);\r\n\r\n  const form = useForm<z.infer<typeof profileSchema>>({\r\n    resolver: zodResolver(profileSchema),\r\n    defaultValues: {\r\n      name: '',\r\n      email: '',\r\n    },\r\n  });\r\n\r\n  const handleSubmit = async (e: React.FormEvent) => {\r\n    e.preventDefault();\r\n    setLoading(true);\r\n\r\n    try {\r\n      const res = await fetch(`http://localhost:8080/profile`, {\r\n        method: 'PUT',\r\n        headers: {\r\n          Authorization: `Bearer ${token}`,\r\n        },\r\n        body: JSON.stringify(detailsProfile),\r\n      });\r\n\r\n      const data = await res.json();\r\n\r\n      toast({\r\n        title: 'Success',\r\n        description: 'Profile updated successfully.',\r\n      });\r\n    } catch (error: any) {\r\n      toast({\r\n        title: 'Error',\r\n        description: error.message || 'Something went wrong.',\r\n        variant: 'destructive',\r\n      });\r\n    } finally {\r\n      setLoading(false);\r\n    }\r\n  };\r\n\r\n  return (\r\n    <div className='min-h-screen bg-gradient-to-br from-white to-purple-100 p-6 flex items-center justify-center'>\r\n      <motion.form\r\n        onSubmit={handleSubmit}\r\n        className='w-full max-w-lg bg-white rounded-xl shadow-md p-6 space-y-4 border border-gray-200'\r\n        initial={{ opacity: 0, y: 40 }}\r\n        animate={{ opacity: 1, y: 0 }}\r\n        transition={{ duration: 0.5 }}\r\n      >\r\n        <h2 className='text-2xl font-bold text-center text-purple-700'>\r\n          Edit Profile\r\n        </h2>\r\n        <Form {...form}>\r\n          <form\r\n            onSubmit={form.handleSubmit(onSubmit)}\r\n            className='space-y-6'\r\n          >\r\n            {/* Email Field */}\r\n            <FormField\r\n              control={form.control}\r\n              name='email'\r\n              render={({ field }) => (\r\n                <FormItem>\r\n                  <FormLabel>Email</FormLabel>\r\n                  <FormControl>\r\n                    <motion.div\r\n                      whileHover={{ scale: 1.02 }}\r\n                      className='relative'\r\n                    >\r\n                      <Mail className='absolute right-3 top-1/2 transform -translate-y-1/2 text-purple-400' />\r\n                      <Input\r\n                        placeholder='your@email.com'\r\n                        className='w-full rounded-lg p-3 pr-10 border-2 border-purple-100 focus:border-purple-500 transition-all'\r\n                        {...field}\r\n                      />\r\n                    </motion.div>\r\n                  </FormControl>\r\n                  <FormMessage />\r\n                </FormItem>\r\n              )}\r\n            />\r\n\r\n            {/* Password Field */}\r\n            <FormField\r\n              control={form.control}\r\n              name='password'\r\n              render={({ field }) => (\r\n                <FormItem>\r\n                  <FormLabel>Password</FormLabel>\r\n                  <FormControl>\r\n                    <motion.div\r\n                      whileHover={{ scale: 1.02 }}\r\n                      className='relative'\r\n                    >\r\n                      <Lock className='absolute right-3 top-1/2 transform -translate-y-1/2 text-purple-400' />\r\n                      <Input\r\n                        type='password'\r\n                        placeholder='••••••••'\r\n                        className='w-full rounded-lg p-3 pr-10 border-2 border-purple-100 focus:border-purple-500 transition-all'\r\n                        {...field}\r\n                      />\r\n                    </motion.div>\r\n                  </FormControl>\r\n                  <FormMessage />\r\n                </FormItem>\r\n              )}\r\n            />\r\n\r\n            <motion.button\r\n              type='submit'\r\n              whileHover={{ scale: 1.03 }}\r\n              whileTap={{ scale: 0.98 }}\r\n              className={`w-full bg-gradient-to-r from-purple-600 to-indigo-600 text-white font-bold py-3 rounded-lg transition-all ${\r\n                form.formState.isSubmitting ? 'opacity-80' : 'hover:shadow-lg'\r\n              }`}\r\n              disabled={form.formState.isSubmitting}\r\n            >\r\n              {form.formState.isSubmitting ? (\r\n                <div className='flex items-center justify-center'>\r\n                  <Loader2 className='animate-spin mr-2' />\r\n                  Save Changes ...\r\n                </div>\r\n              ) : (\r\n                'Sign In'\r\n              )}\r\n            </motion.button>\r\n          </form>\r\n        </Form>\r\n        <Button\r\n          type='submit'\r\n          className='w-full'\r\n        >\r\n          Save Changes\r\n        </Button>\r\n      </motion.form>\r\n    </div>\r\n  );\r\n}\r\n"],"names":[],"mappings":";;;;AACA;AACA;AACA;AACA;AACA;AAAA;AACA;AAEA;AACA;AACA;AAVA;;;;;;;;;;;AAYA,MAAM,gBAAgB,iL