    {"offset": {"line": 90, "column": 0}, "map": {"version":3,"sources":["file://C%3A/Users/Abdalmoute/OneDrive/Desktop/university%20events%20planner/frontend/app/profile/edit/page.tsx"],"sourcesContent":["'use client';\r\nimport { useState } from \"react\";\r\nimport { Input } from \"@/components/ui/input\";\r\nimport { Textarea } from \"@/components/ui/textarea\";\r\nimport { Button } from \"@/components/ui/button\";\r\nimport { useRouter } from \"next/navigation\";\r\nimport { motion } from \"framer-motion\";\r\nimport { useToast } from \"@/hooks/use-toast\";\r\nexport default function EditProfilePage() {\r\n    const router = useRouter();\r\n    const { toast } = useToast();\r\n    const [form, setForm] = useState({\r\n        name: \"Sarah Johnson\",\r\n        email: \"sarah.johnson@uni.edu\",\r\n        university: \"Oxford University\",\r\n        bio: \"\",\r\n    });\r\n\r\n    const [loading, setLoading] = useState(false);\r\n\r\n    const handleChange = (\r\n        e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>\r\n    ) => {\r\n        setForm({ ...form, [e.target.name]: e.target.value });\r\n    };\r\n\r\n    const handleSubmit = async (e: React.FormEvent) => {\r\n        e.preventDefault();\r\n        setLoading(true);\r\n\r\n        try {\r\n            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/user/update`, {\r\n                method: \"PUT\",\r\n                headers: {\r\n                    \"Content-Type\": \"application/json\",\r\n                },\r\n                credentials: \"include\", // لإرسال الـ cookie مع التوكن\r\n                body: JSON.stringify(form),\r\n            });\r\n\r\n            const data = await res.json();\r\n\r\n            if (!res.ok) {\r\n                throw new Error(data.message || \"Failed to update profile\");\r\n            }\r\n\r\n            toast({\r\n                title: \"Success\",\r\n                description: \"Profile updated successfully.\",\r\n            });\r\n        } catch (error: any) {\r\n            toast({\r\n                title: \"Error\",\r\n                description: error.message || \"Something went wrong.\",\r\n                variant: \"destructive\",\r\n            });\r\n        } finally {\r\n            setLoading(false);\r\n        }\r\n    }\r\n\r\n    return (\r\n        <div className=\"min-h-screen bg-gradient-to-br from-white to-purple-100 p-6 flex items-center justify-center\">\r\n            <motion.form\r\n                onSubmit={handleSubmit}\r\n                className=\"w-full max-w-lg bg-white rounded-xl shadow-md p-6 space-y-4 border border-gray-200\"\r\n                initial={{ opacity: 0, y: 40 }}\r\n                animate={{ opacity: 1, y: 0 }}\r\n                transition={{ duration: 0.5 }}\r\n            >\r\n                <h2 className=\"text-2xl font-bold text-center text-purple-700\">Edit Profile</h2>\r\n                <Input name=\"name\" placeholder=\"Name\" value={form.name} onChange={handleChange} />\r\n                <Input name=\"email\" placeholder=\"Email\" value={form.email} onChange={handleChange} />\r\n                <Input name=\"university\" placeholder=\"University\" value={form.university} onChange={handleChange} />\r\n                <textarea\r\n                    name=\"bio\"\r\n                    placeholder=\"Short bio...\"\r\n                    className=\"w-full p-2 rounded-md border border-gray-300\"\r\n                    rows={3}\r\n                    value={form.bio}\r\n                    onChange={handleChange}\r\n                ></textarea>\r\n                <Button type=\"submit\" className=\"w-full\">Save Changes</Button>\r\n            </motion.form>\r\n        </div>\r\n    );\r\n}"],"names":[],"mappings":";;;;AACA;AACA;AAEA;AACA;AACA;AACA;AAPA;;;;;;;;AAQe,SAAS;IACpB,MAAM,SAAS,CAAA,GAAA,kIAAA,CAAA,YAAS,AAAD;IACvB,MAAM,EAAE,KAAK,EAAE,GAAG,CAAA,GAAA,qHAAA,CAAA,WAAQ,AAAD;IACzB,MAAM,CAAC,MAAM,QAAQ,GAAG,CAAA,GAAA,qMAAA